// API endpoint: PUT /api/automated-protocol-optimization/experiments/[id]
// Story 9.3: Automated protocol optimization - Update protocol experiment
// Generated by: VoidBeast V4.0

import { type NextRequest, NextResponse } from "next/server";
import { AutomatedProtocolOptimizationService } from "../../../../lib/services/automated-protocol-optimization";
import { updateProtocolExperimentSchema } from "../../../../lib/validations/automated-protocol-optimization";

const service = new AutomatedProtocolOptimizationService();

// PUT: Update protocol experiment
export async function PUT(request: NextRequest, { params }: { params: { id: string } }) {
  try {
    const { id } = params;
    const body = await request.json();

    if (!id) {
      return NextResponse.json(
        { success: false, error: "Experiment ID is required" },
        { status: 400 },
      );
    }

    // Validate request data
    const validation = updateProtocolExperimentSchema.safeParse(body);
    if (!validation.success) {
      return NextResponse.json(
        {
          success: false,
          error: "Validation failed",
          details: validation.error.format(),
        },
        { status: 400 },
      );
    }

    const updatedExperiment = await service.updateProtocolExperiment(id, validation.data);

    return NextResponse.json({
      success: true,
      data: updatedExperiment,
      message: "Protocol experiment updated successfully",
    });
  } catch (error) {
    console.error("Error updating protocol experiment:", error);
    return NextResponse.json(
      {
        success: false,
        error: "Failed to update protocol experiment",
        details: error instanceof Error ? error.message : "Unknown error",
      },
      { status: 500 },
    );
  }
}
